 import java.util.Arrays;
 ...
+    public List<String> validate(final Topology topology) {
+        Objects.requireNonNull(topology, "topology must not be null");
+        final List<String> warnings = new ArrayList<>();
+
+        final int numStandbyReplicas = getInt(NUM_STANDBY_REPLICAS_CONFIG);
+        if (numStandbyReplicas > 0) {
+            final Set<String> stateStoreNames = topology.internalTopologyBuilder.allStateStoreNames();
+            if (stateStoreNames.isEmpty()) {
+                warnings.add("num.standby.replicas is set to " + numStandbyReplicas +
+                    " but the topology has no state stores. Standby replicas have no effect without stateful processors.");
+            }
+        }
+
+        final String processingGuarantee = getString(PROCESSING_GUARANTEE_CONFIG);
+        if (EXACTLY_ONCE_V2.equals(processingGuarantee)) {
+            warnings.add("processing.guarantee=" + EXACTLY_ONCE_V2 + " requires broker version 2.5 or higher. " +
+                "Ensure all brokers in the cluster meet this requirement.");
+        }
+
+        return warnings;
+    }
